    85→        tolerance: 5, // 5px movement tolerance
    86→      },
    87→    })
    88→  );
    89→
    90→  // Sort columns by order
    91→  const sortedColumns = useMemo(() => {
    92→    return [...columns].sort((a, b) => a.order - b.order);
    93→  }, [columns]);
    94→
    95→  const columnStatuses = sortedColumns.map((col) => col.id);
    96→
    97→  // Get all unique tags from tasks
    98→  const allTags = useMemo(() => {
    99→    const tagSet = new Set<string>();
   100→    tasks.forEach((task) => task.tags.forEach((tag) => tagSet.add(tag)));
   101→    return Array.from(tagSet).sort();
   102→  }, [tasks]);
   103→
   104→  // Filter tasks based on search and filters
   105→  const filteredTasks = useMemo(() => {
   106→    return tasks.filter((task) => {
   107→      // Search filter (title, description, or card number)
   108→      if (searchQuery) {
   109→        const query = searchQuery.toLowerCase();
   110→
   111→        // Phase A: Support searching by card number (e.g., "KAN-1", "1", "kan1")
   112→        const cardNumberStr = task.cardNumber ? `KAN-${task.cardNumber}`.toLowerCase() : '';
   113→        const cardNumberSimple = task.cardNumber?.toString() || '';
   114→
   115→        const matchesSearch =
   116→          task.title.toLowerCase().includes(query) ||
   117→          task.description.toLowerCase().includes(query) ||
   118→          cardNumberStr.includes(query) ||
   119→          cardNumberSimple.includes(query);
   120→
   121→        if (!matchesSearch) return false;
   122→      }
   123→
   124→      // Priority filter
