   146→          const hasSelectedAssignee = taskAssignees.some((id) => selectedAssignees.has(id));
   147→          if (hasSelectedAssignee) return true;
   148→        }
   149→
   150→        // Neither condition met
   151→        if (selectedAssignees.size > 0 || showUnassigned) {
   152→          return false;
   153→        }
   154→      }
   155→
   156→      return true;
   157→    });
