   233→  const handleDragStart = (event: DragStartEvent) => {
   234→    const taskId = event.active.id as string;
   235→    const task = tasks.find((t) => t.id === taskId);
   236→    setActiveTask(task || null);
   237→  };
   238→
   239→  const handleDragEnd = (event: DragEndEvent) => {
   240→    const { active, over } = event;
   241→
   242→    setActiveTask(null);
   243→
   244→    if (!over) return;
   245→
   246→    const taskId = active.id as string;
   247→    const newStatus = over.id as TaskStatus;
   248→
   249→    // WIP Limit validation (Phase 3.3)
   250→    const targetColumn = columns.find((c) => c.id === newStatus);
   251→    const currentTask = tasks.find((t) => t.id === taskId);
   252→    const tasksInTargetColumn = tasks.filter((t) => t.status === newStatus);
   253→
   254→    // Only check WIP limit if moving TO a different column (not reordering within same column)
   255→    if (targetColumn?.wipLimit && currentTask?.status !== newStatus) {
   256→      const enforceStrict = useSettingsStore.getState().enforceWipLimits;
   257→
   258→      // Check if target column is at or over WIP limit
   259→      if (tasksInTargetColumn.length >= targetColumn.wipLimit) {
   260→        if (enforceStrict) {
   261→          // Hard limit: prevent move
   262→          setToast({
   263→            message: `Cannot move task: "${targetColumn.title}" has reached WIP limit (${targetColumn.wipLimit})`,
   264→            showUndo: false,
   265→          });
   266→          return; // Abort move
   267→        } else {
   268→          // Soft limit: show warning but allow move
   269→          setToast({
   270→            message: `Warning: "${targetColumn.title}" is at/over WIP limit (${tasksInTargetColumn.length + 1}/${targetColumn.wipLimit})`,
   271→            showUndo: false,
   272→          });
   273→        }
   274→      }
   275→    }
   276→
   277→    // Move task to new column
   278→    moveTask(taskId, newStatus);
   279→  };
