   290→
   291→  // Phase A: Auto-archive completed tasks on mount
   292→  useEffect(() => {
   293→    autoArchiveCompletedTasks();
   294→  }, []); // Run once on mount
   295→
   296→  // Phase A: Global keyboard shortcut for Quick Add (Cmd/Ctrl+K)
   297→  useEffect(() => {
   298→    const handleGlobalKeyDown = (e: KeyboardEvent) => {
   299→      // Cmd/Ctrl+K to open Quick Add
   300→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
