   557→              // If visibleColumns > actual columns, columns will be narrower (leaving space on right)
   558→              // If visibleColumns < actual columns, horizontal scrolling will be enabled
   559→              const columnWidth = `calc((100% - ${(visibleColumns - 1) * 16}px) / ${visibleColumns})`;
   560→
   561→              return (
   562→                <KanbanColumn
   563→                  key={column.id}
   564→                  id={column.id}
   565→                  title={column.title}
   566→                  color={column.color}
   567→                  wipLimit={column.wipLimit}
   568→                  tasks={filteredTasks.filter((task) => task.status === column.id)}
   569→                  selectedTaskId={selectedColumn === index ? selectedTaskId : undefined}
   570→                  columnWidth={columnWidth}
   571→                  onRegisterRef={(ref) => {
   572→                    columnRefs.current[column.id] = ref;
   573→                  }}
   574→                  onRegisterCardRef={(taskId, ref) => {
   575→                    cardRefs.current[taskId] = ref;
   576→                  }}
   577→                  onCardClick={(task, tab) => {
   578→                    setDetailPanelTaskId(task.id);
   579→                    if (tab) setSelectedTab(tab);
   580→                  }}
   581→                  onEditColumn={handleEditColumn}
   582→                />
   583→              );
   584→            })}
   585→          </div>
   586→
   587→          {/* Drag overlay - shows ghost of dragged card */}
   588→          <DragOverlay>
   589→            {activeTask ? (
   590→              <div className="opacity-80 rotate-3 scale-105 transition-transform">
   591→                <KanbanCard task={activeTask} isDragging />
   592→              </div>
   593→            ) : null}
   594→          </DragOverlay>
   595→        </DndContext>
   596→      ) : (
   597→        <ListView
   598→          tasks={filteredTasks}
   599→          columns={columns}
   600→          onTaskClick={(task) => setDetailPanelTaskId(task.id)}
   601→        />
   602→      )}
   603→
   604→      {/* Keyboard Shortcuts Help Modal */}
   605→      <KeyboardShortcutsHelp isOpen={showHelp} onClose={closeHelp} />
   606→
   607→      {/* Delete Confirmation Dialog */}
   608→      {pendingDeleteTask && (
   609→        <ConfirmDialog
   610→          isOpen={true}
   611→          onClose={cancelDelete}
   612→          onConfirm={confirmDelete}
   613→          title="Delete Task"
   614→          message={`Are you sure you want to delete "${pendingDeleteTask.title}"? This action cannot be undone.`}
   615→          variant="danger"
   616→        />
   617→      )}
   618→
   619→      {/* Column Manager Modal */}
   620→      <ColumnManager
   621→        isOpen={showColumnManager}
   622→        onClose={() => {
   623→          setShowColumnManager(false);
   624→          setColumnManagerInitialId(undefined);
   625→        }}
   626→        initialEditingColumnId={columnManagerInitialId}
   627→      />
   628→
   629→      {/* Toast Notification */}
   630→      {toast && (
   631→        <Toast
   632→          message={toast.message}
   633→          action={toast.showUndo ? { label: 'Undo', onClick: handleUndo } : undefined}
   634→          onClose={() => setToast(null)}
   635→        />
   636→      )}
   637→
   638→      {/* Card Detail Panel */}
   639→      <CardDetailPanel
   640→        task={selectedTask}
   641→        isOpen={!!selectedTask}
   642→        onClose={() => {
   643→          setDetailPanelTaskId(null);
   644→          setSelectedTab('subtasks'); // Reset to default tab
   645→        }}
   646→        onSave={(taskId, updates) => {
   647→          updateTask(taskId, updates);
   648→        }}
   649→        columns={columns}
   650→        initialTab={selectedTab}
   651→        onCardClick={(task) => {
   652→          setDetailPanelTaskId(task.id);
   653→        }}
   654→      />
   655→
   656→      {/* Archived View */}
   657→      <ArchivedView
   658→        isOpen={showArchivedView}
   659→        onClose={() => setShowArchivedView(false)}
   660→      />
   661→
   662→      {/* Quick Add Modal (Phase A: Quick Add Cmd+K) */}
   663→      <QuickAddModal
   664→        isOpen={showQuickAdd}
   665→        onClose={() => setShowQuickAdd(false)}
   666→      />
   667→    </Widget>
   668→  );
