          <KanbanCard task={activeTask} isDragging />
        </div>
      ) : null}
    </DragOverlay>
  </DndContext>
) : viewMode === 'list' ? (
  <ListView
    tasks={filteredTasks}
    columns={columns}
    onTaskClick={(task) => setDetailPanelTaskId(task.id)}
  />
) : (
  <CalendarView
    tasks={filteredTasks}
    columns={columns}
    onTaskClick={(task) => setDetailPanelTaskId(task.id)}
  />
)}

